class SketchJoinOrderServiceTest {

	@Test
	void factorCostBranchRejectsNonFiniteOutputLikeEstimatorBranch() {
		SketchJoinOrderService service = new SketchJoinOrderService(mock(SketchBasedJoinEstimator.class));
		StatementPattern factor = new StatementPattern(new Var("s"), new Var("p"), new Var("o"));

		assertAll(
				() -> assertInvalidEstimateRejected(service, factor, 1.0d, Double.NaN),
				() -> assertInvalidEstimateRejected(service, factor, 1.0d, -1.0d),
				() -> assertInvalidEstimateRejected(service, factor, Double.NaN, 1.0d),
				() -> assertInvalidEstimateRejected(service, factor, -1.0d, 1.0d));
	}

	private static void assertInvalidEstimateRejected(SketchJoinOrderService service, StatementPattern factor,
			double workRows, double outputRows) {
		JoinFactorCostModel factorCostModel = (ignoredFactor, ignoredBindings) -> Optional.of(
				new JoinFactorCostModel.FactorCostEstimate(workRows, outputRows, Map.of(), Map.of()));
		assertTrue(service
				.estimate(List.of(factor), Set.of(), JoinOrderPlanner.Algorithm.GREEDY, factorCostModel)
				.isEmpty());
	}
}
